/// Executor for MFASetup flow
pub struct MFASetupFlowExecutor<H: MFASetupStepHandler>(FlowExecutor<H>);

impl<H: MFASetupStepHandler + Send + Sync + 'static> MFASetupFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self(FlowExecutor::new(handler))
    }

    /// Start a new flow instance
    pub fn start(&self, instance_id: impl Into<String>) -> MFASetupFlowInstance {
        self.0.start(instance_id, MFASetupFlowStep::ValidateUser)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut MFASetupFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            MFASetupFlowStep::ValidateUser => {
                self.0.handler.handle_validate_user(instance).await?
            }
            MFASetupFlowStep::CheckExistingDevice => {
                self.0.handler.handle_check_existing_device(instance).await?
            }
            MFASetupFlowStep::CheckCanAdd => {
                let next = self.0.handler.evaluate_check_can_add(instance).await?;
                Some(next)
            }
            MFASetupFlowStep::RouteByType => {
                let next = self.0.handler.evaluate_route_by_type(instance).await?;
                Some(next)
            }
            MFASetupFlowStep::GenerateTotpSecret => {
                self.0.handler.handle_generate_totp_secret(instance).await?
            }
            MFASetupFlowStep::CreateTotpDevice => {
                self.0.handler.handle_create_totp_device(instance).await?
            }
            MFASetupFlowStep::WaitTotpVerification => {
                self.0.handler.handle_wait_totp_verification(instance).await?
            }
            MFASetupFlowStep::VerifyPhoneNumber => {
                self.0.handler.handle_verify_phone_number(instance).await?
            }
            MFASetupFlowStep::CreateSmsDevice => {
                self.0.handler.handle_create_sms_device(instance).await?
            }
            MFASetupFlowStep::WaitSmsVerification => {
                self.0.handler.handle_wait_sms_verification(instance).await?
            }
            MFASetupFlowStep::ActivateDevice => {
                self.0.handler.handle_activate_device(instance).await?
            }
            MFASetupFlowStep::GenerateBackupCodes => {
                self.0.handler.handle_generate_backup_codes(instance).await?
            }
            MFASetupFlowStep::CreateBackupDevice => {
                self.0.handler.handle_create_backup_device(instance).await?
            }
            MFASetupFlowStep::EnableMfaOnUserSettings => {
                self.0.handler.handle_enable_mfa_on_user_settings(instance).await?
            }
            MFASetupFlowStep::SendMfaEnabledEmail => {
                self.0.handler.handle_send_mfa_enabled_email(instance).await?
            }
            MFASetupFlowStep::LogMfaSetup => {
                self.0.handler.handle_log_mfa_setup(instance).await?
            }
            MFASetupFlowStep::Complete => {
                self.0.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            MFASetupFlowStep::ErrorExistingTotp => {
                self.0.handler.handle_error_existing_totp(instance).await?
            }
            MFASetupFlowStep::ErrorEnd => {
                self.0.handler.handle_error_end(instance).await?;
                None // Terminal step
            }
            MFASetupFlowStep::SetupTimeout => {
                self.0.handler.handle_setup_timeout(instance).await?
            }
            MFASetupFlowStep::LogTimeout => {
                self.0.handler.handle_log_timeout(instance).await?
            }
            MFASetupFlowStep::TimeoutEnd => {
                self.0.handler.handle_timeout_end(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = FlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut MFASetupFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != FlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut MFASetupFlowInstance) { self.0.cancel(instance) }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut MFASetupFlowInstance, error: impl Into<String>) { self.0.fail(instance, error) }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = MFASetupFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, FlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = MFASetupFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = MFASetupFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = FlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = FlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}
